+            }
+            let base_hex = if noise > 0.6 { 0xffffff } else { 0x0f172a };
+            let color = apply_palette(rgba_from_hex(base_hex, alpha.clamp(0.01, 0.12)), palette);
+            let x = f32::from(origin.x) + col as f32 * cell_w;
